import React, { useEffect, useState } from "react";
import api from "../utils/api";

const formatCurrency = (value = 0) =>
  Number(value).toLocaleString("en-IN", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  });

const AdminDashboard = () => {
  const [users, setUsers] = useState([]);
  const [analytics, setAnalytics] = useState(null);
  const [selectedUser, setSelectedUser] = useState(null);
  const [userData, setUserData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const FRONTEND_URL = process.env.REACT_APP_FRONTEND_URL || "http://localhost:3001";

  // Fetch all users and analytics
  useEffect(() => {
    const fetchAdmin = async () => {
      try {
        const [usersRes, analyticsRes] = await Promise.all([
          api.get("/admin/users"),
          api.get("/admin/analytics"),
        ]);
        setUsers(usersRes.data);
        setAnalytics(analyticsRes.data);
      } catch (err) {
        console.error("Admin fetch error:", err);
        setError("Access denied or failed to load admin data.");
      } finally {
        setLoading(false);
      }
    };
    fetchAdmin();
  }, []);

  // Fetch specific user data
  const viewUser = async (userId) => {
    try {
      setSelectedUser(userId);
      const res = await api.get(`/admin/user/${userId}`);
      setUserData(res.data);
    } catch (err) {
      console.error("Failed to fetch user data:", err);
    }
  };

  const handleLogout = () => {
    localStorage.clear();
    window.location.href = `${FRONTEND_URL}/login`;
  };

  if (loading) return <div className="admin-loading">Loading admin panel...</div>;
  if (error) return <div className="admin-error">{error}</div>;

  return (
    <div className="admin-dashboard">
      {/* Header */}
      <header className="admin-header">
        <div className="admin-header-left">
          <h1>⚙️ Wave Admin Panel</h1>
          <span className="admin-badge">ADMIN</span>
        </div>
        <button className="admin-logout-btn" onClick={handleLogout}>
          Logout
        </button>
      </header>

      {/* Analytics Cards */}
      {analytics && (
        <div className="admin-stats-grid">
          <div className="admin-stat-card">
            <p className="admin-stat-label">Total Users</p>
            <h3 className="admin-stat-value">{analytics.totalUsers}</h3>
          </div>
          <div className="admin-stat-card">
            <p className="admin-stat-label">Total Orders</p>
            <h3 className="admin-stat-value">{analytics.totalOrders}</h3>
          </div>
          <div className="admin-stat-card">
            <p className="admin-stat-label">Total Volume</p>
            <h3 className="admin-stat-value">₹{formatCurrency(analytics.totalVolume)}</h3>
          </div>
          <div className="admin-stat-card">
            <p className="admin-stat-label">Platform P&L</p>
            <h3 className={`admin-stat-value ${analytics.platformPnL >= 0 ? "profit" : "loss"}`}>
              ₹{formatCurrency(analytics.platformPnL)}
            </h3>
          </div>
        </div>
      )}

      {/* Top Traded Stocks */}
      {analytics && analytics.topStocks.length > 0 && (
        <div className="admin-section">
          <h2>🔥 Most Traded Stocks</h2>
          <div className="admin-top-stocks">
            {analytics.topStocks.map((stock, i) => (
              <div key={i} className="admin-stock-pill">
                <span className="admin-stock-rank">#{i + 1}</span>
                <span className="admin-stock-name">{stock.name}</span>
                <span className="admin-stock-qty">{stock.totalQty} units</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Users Table */}
      <div className="admin-section">
        <h2>👥 All Users ({users.length})</h2>
        <div className="admin-table-wrap">
          <table className="admin-table">
            <thead>
              <tr>
                <th>Name</th>
                <th>Email</th>
                <th>Balance</th>
                <th>Joined</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
              {users.map((user) => (
                <tr
                  key={user._id}
                  className={selectedUser === user._id ? "selected" : ""}
                >
                  <td>{user.name}</td>
                  <td>{user.email}</td>
                  <td>₹{formatCurrency(user.balance)}</td>
                  <td>{new Date(user.createdAt).toLocaleDateString("en-IN")}</td>
                  <td>
                    <button
                      className="admin-view-btn"
                      onClick={() => viewUser(user._id)}
                    >
                      View Details
                    </button>
                  </td>
                </tr>
              ))}
              {users.length === 0 && (
                <tr>
                  <td colSpan="5" style={{ textAlign: "center", padding: "40px", color: "#94a3b8" }}>
                    No users registered yet.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Selected User Details */}
      {userData && (
        <div className="admin-section admin-user-detail">
          <h2>📋 {userData.user.name}'s Portfolio</h2>
          <p className="admin-user-email">{userData.user.email}</p>

          {/* User Analytics */}
          <div className="admin-user-stats">
            <div className="admin-mini-stat">
              <span className="admin-mini-label">Balance</span>
              <span className="admin-mini-value">₹{formatCurrency(userData.user.balance)}</span>
            </div>
            <div className="admin-mini-stat">
              <span className="admin-mini-label">Investment</span>
              <span className="admin-mini-value">₹{formatCurrency(userData.analytics.totalInvestment)}</span>
            </div>
            <div className="admin-mini-stat">
              <span className="admin-mini-label">Current Value</span>
              <span className="admin-mini-value">₹{formatCurrency(userData.analytics.totalCurrentValue)}</span>
            </div>
            <div className="admin-mini-stat">
              <span className="admin-mini-label">P&L</span>
              <span className={`admin-mini-value ${userData.analytics.totalPnL >= 0 ? "profit" : "loss"}`}>
                ₹{formatCurrency(userData.analytics.totalPnL)}
              </span>
            </div>
            <div className="admin-mini-stat">
              <span className="admin-mini-label">Total Orders</span>
              <span className="admin-mini-value">{userData.analytics.totalOrders}</span>
            </div>
            <div className="admin-mini-stat">
              <span className="admin-mini-label">Buy / Sell</span>
              <span className="admin-mini-value">
                {userData.analytics.buyOrders} / {userData.analytics.sellOrders}
              </span>
            </div>
          </div>

          {/* User Holdings */}
          {userData.holdings.length > 0 && (
            <>
              <h3>Holdings ({userData.holdings.length})</h3>
              <div className="admin-table-wrap">
                <table className="admin-table">
                  <thead>
                    <tr>
                      <th>Stock</th>
                      <th>Qty</th>
                      <th>Avg</th>
                      <th>LTP</th>
                      <th>P&L</th>
                    </tr>
                  </thead>
                  <tbody>
                    {userData.holdings.map((h, i) => {
                      const pnl = (h.price - h.avg) * h.qty;
                      return (
                        <tr key={i}>
                          <td>{h.name}</td>
                          <td>{h.qty}</td>
                          <td>₹{formatCurrency(h.avg)}</td>
                          <td>₹{formatCurrency(h.price)}</td>
                          <td className={pnl >= 0 ? "profit" : "loss"}>
                            ₹{formatCurrency(pnl)}
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </>
          )}

          {/* User Orders */}
          {userData.orders.length > 0 && (
            <>
              <h3>Recent Orders ({userData.orders.length})</h3>
              <div className="admin-table-wrap">
                <table className="admin-table">
                  <thead>
                    <tr>
                      <th>Stock</th>
                      <th>Qty</th>
                      <th>Price</th>
                      <th>Mode</th>
                      <th>Date</th>
                    </tr>
                  </thead>
                  <tbody>
                    {userData.orders.slice(0, 20).map((o, i) => (
                      <tr key={i}>
                        <td>{o.name}</td>
                        <td>{o.qty}</td>
                        <td>₹{formatCurrency(o.price)}</td>
                        <td className={o.mode === "BUY" ? "profit" : "loss"}>{o.mode}</td>
                        <td>{new Date(o.createdAt).toLocaleString("en-IN")}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </>
          )}
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;
